    # ── Image Handling ─────────────────────────────────────────────────
    def _load_images(self):
        if not PIL_AVAILABLE:
            return
        try:
            import io
            # Load banner from embedded base64
            banner_bytes = base64.b64decode(BANNER_B64)
            img = Image.open(io.BytesIO(banner_bytes))
            self.bg_image_pil = ImageEnhance.Brightness(img).enhance(0.50)
        except Exception as e:
            print(f"Banner load error: {e}")
            self.bg_image_pil = None
        try:
            import io
            # Load logo from embedded base64
            logo_bytes = base64.b64decode(LOGO_B64)
            logo = Image.open(io.BytesIO(logo_bytes)).resize((130, 65), Image.LANCZOS)
            self.logo_photo = ImageTk.PhotoImage(logo)
            self._img_refs.append(self.logo_photo)
        except Exception as e:
            print(f"Logo load error: {e}")
            self.logo_photo = None

    def _on_resize(self, event):
        if event.widget == self.root:
            self._update_banner()

    def _update_banner(self):
        if not (PIL_AVAILABLE and self.bg_image_pil and hasattr(self, '_banner_canvas')):
            return
        try:
            w = self._banner_canvas.winfo_width()
            h = self._banner_canvas.winfo_height()
            if w > 1 and h > 1:
                photo = ImageTk.PhotoImage(
                    self.bg_image_pil.resize((w, h), Image.LANCZOS))
                self._img_refs.append(photo)
                self._banner_canvas.itemconfig(self._banner_img_id, image=photo)
                self._banner_canvas.coords(self._banner_img_id, 0, 0)
        except:
            pass

    def center_window(self):
        self.root.update_idletasks()
        w = self.root.winfo_width()
        h = self.root.winfo_height()
        x = (self.root.winfo_screenwidth()  // 2) - (w // 2)
        y = (self.root.winfo_screenheight() // 2) - (h // 2)
        self.root.geometry(f'{w}x{h}+{x}+{y}')

