            df['Program'] = df['Program'].str.replace('BCA MCA',  'BCA+MCA',  regex=False)
            df['Program'] = df['Program'].str.replace('BCOM MBA', 'BCOM+MBA', regex=False)
            self.log("   ✓ Programs normalized")

