            mask = ~df['Email'].astype(str).str.contains('@amityonline.com', na=False)
            deleted = df[mask].copy()
            deleted['Deletion_Reason'] = 'Email is not @amityonline.com'
            deleted_rows.append(deleted); df = df[~mask]
            self.log(f"   ✓ {len(deleted):,} removed")

            self.log("🔄 3/7: Filtering enrollments...")
            df['Enrollment'] = df['Enrollment'].astype(str).str.strip()
            mask = ~(df['Enrollment'].str.startswith('A99') |
                     df['Enrollment'].str.startswith('A193'))
            deleted = df[mask].copy()
            deleted['Deletion_Reason'] = 'Enrollment not A99 or A193'
            deleted_rows.append(deleted); df = df[~mask]
            self.log(f"   ✓ {len(deleted):,} removed")

            self.log("🔄 4/7: Filtering -P enrollments...")
            df['Batch_first_half'] = df['Batch'].astype(str).apply(
                lambda x: x.split('-')[0] if '-' in x else x)
            mask = (df['Enrollment'].str.endswith('-P') &
                    (df['Batch_first_half'] != 'Jan26'))
            deleted = df[mask].copy()
            deleted['Deletion_Reason'] = 'Enrollment ends with -P (older batch)'
            deleted_rows.append(deleted); df = df[~mask]
            self.log(f"   ✓ {len(deleted):,} removed")

            self.log("🔄 5/7: Filtering programs...")
            mask = ~df['Program'].isin(self.allowed_programs)
            deleted = df[mask].copy()
            deleted['Deletion_Reason'] = 'Program not in allowed list'
            deleted_rows.append(deleted); df = df[~mask]
            self.log(f"   ✓ {len(deleted):,} removed")

            self.log("🔄 6/7: Applying period filter...")
            if period_type == 'single-period':
                bs = ms = [baseline]
            elif period_type == 'n-period':
                bs = self.calculate_previous_sessions(baseline, 6)
                ms = self.calculate_previous_sessions(baseline, 4)
            else:
                bs = self.calculate_previous_sessions(baseline, 12)
                ms = self.calculate_previous_sessions(baseline, 8)

            bm = ((df['Program'].astype(str).str.contains('BACHELOR', case=False, na=False) |
                   df['Program'].astype(str).str.contains(r'\+', na=False)) &
                  df['Batch_first_half'].isin(bs))
            mm = ((df['Program'].astype(str).str.contains('MASTER', case=False, na=False) &
                   ~df['Program'].astype(str).str.contains(r'\+', na=False)) &
                  df['Batch_first_half'].isin(ms))
            keep    = bm | mm
            deleted = df[~keep].copy()
            deleted['Deletion_Reason'] = f'Outside {period_type} range'
            deleted_rows.append(deleted)
            df = df[keep].drop('Batch_first_half', axis=1)
            self.log(f"   ✓ {len(deleted):,} removed")

            self.log("🔄 7/7: Creating pivots...")
            all_del = pd.concat(deleted_rows, ignore_index=True) if deleted_rows else pd.DataFrame()
            if 'Batch_first_half' in all_del.columns:
                all_del = all_del.drop('Batch_first_half', axis=1)

            pp = df.groupby('Program')['Enrollment'].count().reset_index()
            pp.columns = ['Program', 'Count']
            pp = pp.sort_values('Count', ascending=False)
            pp.loc[len(pp)] = ['TOTAL', pp['Count'].sum()]

            pb = df.groupby('Batch')['Enrollment'].count().reset_index()
            pb.columns = ['Batch', 'Count']
            pb.loc[len(pb)] = ['TOTAL', pb['Count'].sum()]

            n = max(len(pp), len(pb))
            pivot = pd.DataFrame(index=range(n))
            pivot['Program']       = pp['Program'].reset_index(drop=True)
            pivot['Program_Count'] = pp['Count'].reset_index(drop=True)
            pivot['']              = ''
            pivot['Batch']         = pb['Batch'].reset_index(drop=True)
            pivot['Batch_Count']   = pb['Count'].reset_index(drop=True)
